<?php
namespace App\Services;use App\Models\ServiceRecord;use Carbon\Carbon;
class UpcomingServiceCalendarService{public function events(Carbon $start,Carbon $end):array{return ServiceRecord::with('machine.client')->whereNotNull('next_service_due')->where('next_service_due','>=',$start->toDateString())->where('next_service_due','<',$end->toDateString())->get()->map(function($s){$m=$s->machine;$c=$m?->client;$name=$c?->company_name?:$c?->trading_name?:'Unknown Client';$model=trim(($m?->brand.' '.$m?->model))?:'Machine';return['id'=>'service-'.$s->id,'title'=>'Service Due – '.$name.' – '.$model,'start'=>$s->next_service_due->toDateString(),'allDay'=>true,'sourceType'=>'upcoming_service','editable'=>false,'extendedProps'=>['serviceRecordId'=>$s->id,'clientId'=>$c?->id,'machineId'=>$m?->id,'clientName'=>$name,'machineBrand'=>$m?->brand,'machineModel'=>$m?->model,'serialNumber'=>$m?->serial_number,'refrigerantType'=>$m?->refrigerant_type,'status'=>$s->status,'technician'=>$s->technician_name,'notes'=>$s->notes]];})->all();}}
